 1	import * as React from "react";
 2	import {
 3	  Checkbox,
 4	  FormGroup,
 5	  FormHelperText,
 6	  HelperText,
 7	  HelperTextItem,
 8	} from "@patternfly/react-core";
 9	import { useField } from "formik";
10	import { FieldProps } from "../../copiedFromConsole/formik-fields/field-types";
11	import { omit } from "lodash-es";
12	import { ExclamationCircleIcon } from "@patternfly/react-icons";
13	
14	export type CheckboxFieldProps = FieldProps & {
15	  formLabel?: string;
16	  value?: string;
17	  onChange?: (val: boolean) => void;
18	};
19	
20	const CheckboxField = ({
21	  label,
22	  formLabel,
23	  helpText,
24	  required,
25	  onChange,
26	  name,
27	  labelIcon,
28	  ...props
29	}: CheckboxFieldProps) => {
30	  const [field, { touched, error }] = useField<boolean>(name);
31	  const isValid = !(touched && error);
32	  const errorMessage = !isValid ? error : "";
33	
34	  const validated = isValid ? "default" : "error";
35	
36	  return (
37	    <FormGroup
38	      fieldId={name}
39	      label={formLabel}
40	      isRequired={required}
41	      labelHelp={labelHelp}
42	    >
43	      <Checkbox
44	        {...{
45	          ...omit(field, ["value"]),
46	          ...props,
47	          checked: field.value,
48	          id: name,
49	          label,
50	          isChecked: field.value,
51	          isValid,
52	          "aria-describedby": helpText ? `${name}-helper` : undefined,
53	          onChange: (event, val) => {
54	            field.onChange(event);
55	            onChange && onChange(val);
56	          },
57	        }}
58	      />
59	      <FormHelperText>
60	        <HelperText>
61	          <HelperTextItem
62	            variant={validated}
63	            {...(validated === "error" && { icon: <ExclamationCircleIcon /> })}
64	          >
65	            {errorMessage || helpText}
66	          </HelperTextItem>
67	        </HelperText>
68	      </FormHelperText>
69	    </FormGroup>
70	  );
71	};
72	
73	export default CheckboxField;

